'use client'

import { useEffect, useMemo, useState, useTransition } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import { Banknote, ChevronLeft, ChevronRight, CircleDollarSign, ClockAlert, FileText, HardDriveDownload, LayoutDashboard, LogOut, Menu, Monitor, Palette, Plus, QrCode, Search, Trash2, UserRoundCog, WalletCards, X } from 'lucide-react'
import { toast } from 'sonner'
import { authClient } from '@/lib/auth-client'
import { buyoutRentalItem, changeStatus, collectPayment, createRental, getCustomerHistory, recordDepositAction, renewRentalItems, reversePayment, type PaymentInput, type RentalInput, type RentalItemInput, type RenewalInput } from '@/app/actions/rentals'
import { exchangeRentalItem, reportLostItem, returnRentalItem, type ExchangeInput, type LossInput, type ReturnInput } from '@/app/actions/operations'
import { changeRentalItem, createRepairRecord, type RentalChangeInput, type RepairInput } from '@/app/actions/rental-events'

type Item = { id:number; rentalId:number; deviceName:string; deviceType:string; deviceCode:string|null; deviceConfig:string|null; quantity:number; startDate:string|null; endDate:string|null; monthlyRent:string; totalRent:string; boughtOutQuantity:number; returnedQuantity:number; lostQuantity:number; buyoutAmount:string; cpu:string|null;motherboard:string|null;memory:string|null;storage:string|null;graphicsCard:string|null;powerSupply:string|null;caseModel:string|null;monitorInfo:string|null;screenSize:string|null;screenResolution:string|null;refreshRate:string|null;panelType:string|null;ports:string|null;batteryInfo:string|null;adapterInfo:string|null;accessories:string|null;colorGamut:string|null }
type Buyout = { id:number; rentalItemId:number; quantity:number; unitPrice:string; amount:string; buyoutDate:string; notes:string|null }
type Renewal = { id:number; rentalId:number; sourceRentalItemId:number; renewedRentalItemId:number; quantity:number; renewalMonths:number|null; billingUnit:string|null; duration:number|null; unitPrice:string|null; oldMonthlyRent:string; newMonthlyRent:string; oldEndDate:string; newEndDate:string; renewalAmount:string; renewalDate:string; notes:string|null }
type Payment = { id:number; rentalId:number; renewalRecordId:number|null; amount:string; paymentDate:string; paymentMethod:string; feeType:string; notes:string|null }
type RentalEvent = { id:number;eventType:string;status:string;eventDate:string;itemId:number|null;beforeSnapshot:unknown;afterSnapshot:unknown;reason:string|null;feeAdjustment:string;repairCost:string;customerCharge:string;faultDescription:string|null;resolution:string|null;completedDate:string|null;operatorName:string;notes:string|null }
type Bill = { id:number;billNo:string;periodStart:string;periodEnd:string;dueDate:string;billType:string;amount:string;paidAmount:string;status:string;notes:string|null }
type Ledger = { id:number;entryType:string;amount:string;entryDate:string;paymentRecordId:number|null;operatorName:string;notes:string|null }
type Rental = { id:number;contractNo:string;customerCompany:string|null;customerName:string;customerPhone:string;customerAddress:string|null;deviceName:string;deviceType:string;quantity:number;startDate:string;endDate:string;monthlyRent:string;totalRent:string;deposit:string;paidAmount:string;paymentStatus:string;status:string;notes:string|null;items:Item[];buyoutRecords:Buyout[];renewalRecords:Renewal[];paymentRecords:Payment[];events:RentalEvent[];bills:Bill[];ledger:Ledger[] }
type Summary={total:number;active:number;overdue:number;revenue:string;receivable:string}
const money=(n:string|number)=>new Intl.NumberFormat('zh-CN',{style:'currency',currency:'CNY',maximumFractionDigits:0}).format(Number(n))
const today=()=>new Date().toISOString().slice(0,10)
const emptyItem=():RentalItemInput=>({deviceName:'',deviceType:'台式机',deviceCode:'',deviceConfig:'',quantity:1,monthlyRent:0,totalRent:0,cpu:'',motherboard:'',memory:'',storage:'',graphicsCard:'',powerSupply:'',caseModel:'',monitorInfo:'',screenSize:'',screenResolution:'',refreshRate:'',panelType:'',ports:'',batteryInfo:'',adapterInfo:'',accessories:'',colorGamut:''})
const emptyRental=():RentalInput=>({contractNo:'',customerCompany:'',customerName:'',customerPhone:'',customerAddress:'',startDate:today(),endDate:'',deposit:0,notes:'',items:[emptyItem()]})

export function Dashboard({storeName,userName,role,permissions,summary,rentals}:{storeName:string;userName:string;role:'admin'|'employee';permissions:string[];summary:Summary;rentals:Rental[]}){
  const router=useRouter(); const[pending,start]=useTransition(); const[query,setQuery]=useState(''); const[status,setStatus]=useState('全部'); const[page,setPage]=useState(1); const[mobileMenu,setMobileMenu]=useState(false); const[dialog,setDialog]=useState<'new'|'detail'|'renew'|'payment'|'buyout'|'history'|'return'|'loss'|'change'|'repair'|'deposit'|'exchange'|null>(null); const[selected,setSelected]=useState<Rental|null>(null); const[form,setForm]=useState<RentalInput>(emptyRental())
  const filtered=useMemo(()=>rentals.filter(r=>(status==='全部'||r.status===status)&&`${r.contractNo}${r.customerCompany||''}${r.customerName}${r.customerPhone}${r.deviceName}`.toLowerCase().includes(query.toLowerCase())),[rentals,query,status])
  const pageSize=8; const pageCount=Math.max(1,Math.ceil(filtered.length/pageSize)); const visible=filtered.slice((page-1)*pageSize,page*pageSize)
  useEffect(()=>setPage(1),[query,status])
  useEffect(()=>{if(page>pageCount)setPage(pageCount)},[page,pageCount])
  const can=(permission:string)=>role==='admin'||permissions.includes(permission)
  const run=(fn:()=>Promise<void>,message:string)=>start(async()=>{try{await fn();toast.success(message);setDialog(null);router.refresh()}catch(error){toast.error(error instanceof Error?error.message:'操作失败')}})
  const openDetail=(r:Rental)=>{setSelected(r);setDialog('detail')}
  return <div className="min-h-svh bg-background"><header className="sticky top-0 z-10 flex h-16 items-center justify-between border-b bg-card px-4 md:px-6"><div className="flex items-center gap-3"><button type="button" aria-label="打开功能菜单" aria-expanded={mobileMenu} onClick={()=>setMobileMenu(true)} className="rounded-lg border p-2 md:hidden"><Menu className="size-5"/></button><span className="flex size-9 items-center justify-center rounded-lg bg-primary text-primary-foreground"><Monitor className="size-5"/></span><div><p className="max-w-40 truncate font-semibold sm:max-w-64">{storeName}</p><p className="text-xs text-muted-foreground">门店业务工作台</p></div></div><div className="flex items-center gap-3"><div className="hidden text-right sm:block"><p className="text-sm font-medium">{userName}</p><p className="text-xs text-muted-foreground">{role==='admin'?'管理员':'员工账号'}</p></div><button aria-label="退出登录" className="rounded-lg border p-2" onClick={async()=>{await authClient.signOut();router.push('/sign-in');router.refresh()}}><LogOut className="size-5"/></button></div></header>
  {mobileMenu&&<div className="fixed inset-0 z-40 md:hidden"><button type="button" aria-label="关闭功能菜单" className="absolute inset-0 bg-foreground/30" onClick={()=>setMobileMenu(false)}/><aside aria-label="手机功能菜单" className="absolute inset-y-0 left-0 flex w-72 flex-col bg-card p-4 shadow-xl"><div className="flex items-center justify-between border-b pb-4"><div><p className="font-semibold">功能菜单</p><p className="text-xs text-muted-foreground">{userName} · {role==='admin'?'管理员':'员工账号'}</p></div><button type="button" aria-label="关闭功能菜单" onClick={()=>setMobileMenu(false)} className="rounded-lg border p-2"><X className="size-5"/></button></div><nav className="mt-4 flex flex-col gap-1"><button type="button" onClick={()=>setMobileMenu(false)} className="flex items-center gap-3 rounded-lg bg-primary px-3 py-3 text-left text-sm font-medium text-primary-foreground"><LayoutDashboard className="size-5"/>经营总览</button>{can('资金查看')&&<Link href="/finance" className="flex items-center gap-3 rounded-lg px-3 py-3 text-sm hover:bg-muted"><Banknote className="size-5"/>资金流水</Link>}{can('账号管理')&&<Link href="/accounts" className="flex items-center gap-3 rounded-lg px-3 py-3 text-sm hover:bg-muted"><UserRoundCog className="size-5"/>账号管理</Link>}{can('系统设置')&&<Link href="/settings" className="flex items-center gap-3 rounded-lg px-3 py-3 text-sm hover:bg-muted"><Palette className="size-5"/>系统设置</Link>}{role==='admin'&&<Link href="/customer-portals" className="flex items-center gap-3 rounded-lg px-3 py-3 text-sm hover:bg-muted"><QrCode className="size-5"/>客户门户</Link>}{role==='admin'&&<Link href="/backup" className="flex items-center gap-3 rounded-lg px-3 py-3 text-sm hover:bg-muted"><HardDriveDownload className="size-5"/>版本与备份</Link>}</nav></aside></div>}
  <nav aria-label="手机快捷导航" className="fixed inset-x-0 bottom-0 z-30 grid grid-cols-2 border-t bg-card px-2 pb-[env(safe-area-inset-bottom)] md:hidden"><button type="button" className="flex min-h-16 flex-col items-center justify-center gap-1 text-xs font-medium text-primary"><LayoutDashboard className="size-5"/>经营总览</button>{can('资金查看')?<Link href="/finance" className="flex min-h-16 flex-col items-center justify-center gap-1 text-xs text-muted-foreground"><Banknote className="size-5"/>资金流水</Link>:<button type="button" onClick={()=>setMobileMenu(true)} className="flex min-h-16 flex-col items-center justify-center gap-1 text-xs text-muted-foreground"><Menu className="size-5"/>全部功能</button>}</nav>
  <div className="flex pb-20 md:pb-0"><aside className="hidden min-h-[calc(100svh-4rem)] w-56 border-r bg-card p-4 md:block"><nav className="flex flex-col gap-1"><div className="flex items-center gap-3 rounded-lg bg-primary px-3 py-2.5 text-sm font-medium text-primary-foreground"><LayoutDashboard className="size-5"/>经营总览</div>{can('资金查看')&&<Link href="/finance" className="flex items-center gap-3 rounded-lg px-3 py-2.5 text-sm hover:bg-muted"><Banknote className="size-5"/>资金流水</Link>}{can('账号管理')&&<Link href="/accounts" className="flex items-center gap-3 rounded-lg px-3 py-2.5 text-sm hover:bg-muted"><UserRoundCog className="size-5"/>账号管理</Link>}{can('系统设置')&&<Link href="/settings" className="flex items-center gap-3 rounded-lg px-3 py-2.5 text-sm hover:bg-muted"><Palette className="size-5"/>系统设置</Link>}{role==='admin'&&<Link href="/customer-portals" className="flex items-center gap-3 rounded-lg px-3 py-2.5 text-sm hover:bg-muted"><QrCode className="size-5"/>客户门户</Link>}{role==='admin'&&<Link href="/backup" className="flex items-center gap-3 rounded-lg px-3 py-2.5 text-sm hover:bg-muted"><HardDriveDownload className="size-5"/>版本与备份</Link>}</nav></aside><main className="min-w-0 flex-1 p-4 md:p-6"><div className="mx-auto flex max-w-7xl flex-col gap-6"><div className="flex flex-col justify-between gap-3 sm:flex-row sm:items-center"><div><h1 className="text-2xl font-bold text-balance">经营总览</h1><p className="text-sm text-muted-foreground">管理合同、设备明细、收款与买断进度</p></div><button onClick={()=>{setForm(emptyRental());setDialog('new')}} className="flex h-10 items-center justify-center gap-2 rounded-lg bg-primary px-4 font-medium text-primary-foreground"><Plus className="size-4"/>新增租赁</button></div>
  <div className="grid grid-cols-2 gap-3 lg:grid-cols-4"><Stat label="租赁合同" value={summary.total} icon={<Monitor/>}/><Stat label="在租合同" value={summary.active} icon={<LayoutDashboard/>}/><Stat label="逾期合同" value={summary.overdue} icon={<ClockAlert/>}/><Stat label="累计收款" value={money(summary.revenue)} icon={<WalletCards/>}/></div>
  <section className="overflow-hidden rounded-xl border bg-card"><div className="flex flex-col gap-3 border-b p-4 sm:flex-row sm:items-center sm:justify-between"><div><h2 className="font-semibold">租赁记录</h2><p className="text-sm text-muted-foreground">共 {filtered.length} 条记录</p></div><div className="flex gap-2"><label className="flex h-10 min-w-0 flex-1 items-center gap-2 rounded-lg border px-3 sm:w-72"><Search className="size-4 text-muted-foreground"/><input value={query} onChange={e=>setQuery(e.target.value)} className="min-w-0 flex-1 bg-transparent text-sm outline-none" placeholder="合同、客户或设备"/></label><select aria-label="租赁状态" value={status} onChange={e=>setStatus(e.target.value)} className="h-10 rounded-lg border bg-background px-3">{['全部','在租','逾期','部分买断','部分退租','部分丢失','丢失','买断','已退租','已结束'].map(s=><option key={s}>{s}</option>)}</select></div></div>
  <div className="overflow-x-auto"><table className="w-full min-w-[900px] text-left text-sm"><thead className="bg-muted text-muted-foreground"><tr><th className="p-3">合同编号</th><th className="p-3">客户</th><th className="p-3">设备明细</th><th className="p-3">数量</th><th className="p-3">租期</th><th className="p-3">合同金额</th><th className="p-3">状态</th></tr></thead><tbody>{visible.map(r=><tr key={r.id} onClick={()=>openDetail(r)} className="cursor-pointer border-t hover:bg-muted/50"><td className="p-3 font-medium">{r.contractNo}</td><td className="p-3"><p className="font-medium">{r.customerCompany||r.customerName}</p><p className="text-xs text-muted-foreground">{r.customerCompany?`${r.customerName} · `:''}{r.customerPhone}</p></td><td className="p-3">{r.items.length} 项 · {r.items.map(i=>i.deviceName).join('、')}</td><td className="p-3">{r.quantity}</td><td className="p-3">{r.startDate} 至 {r.endDate}</td><td className="p-3">{money(r.totalRent)}</td><td className="p-3"><Status value={r.status}/></td></tr>)}</tbody></table>{!filtered.length&&<p className="p-10 text-center text-sm text-muted-foreground">暂无符合条件的租赁记录</p>}</div>{filtered.length>pageSize&&<div className="flex items-center justify-between border-t px-4 py-3"><p className="text-xs text-muted-foreground">第 {page} / {pageCount} 页</p><div className="flex gap-2"><button type="button" aria-label="上一页" disabled={page===1} onClick={()=>setPage(value=>Math.max(1,value-1))} className="rounded-lg border p-2 disabled:opacity-40"><ChevronLeft className="size-4"/></button><button type="button" aria-label="下一页" disabled={page===pageCount} onClick={()=>setPage(value=>Math.min(pageCount,value+1))} className="rounded-lg border p-2 disabled:opacity-40"><ChevronRight className="size-4"/></button></div></div>}</section></div></main></div>
  <Dialog open={dialog==='new'} title="新增租赁合同" wide onClose={()=>setDialog(null)}><RentalForm form={form} setForm={setForm} pending={pending} submit={()=>run(()=>createRental(form),'租赁合同已创建')}/></Dialog>
  <Dialog open={dialog==='detail'} title={selected?.contractNo||'租赁详情'} wide onClose={()=>setDialog(null)}>{selected&&<Detail rental={selected} onPayment={()=>setDialog('payment')} onRenew={()=>setDialog('renew')} onBuyout={()=>setDialog('buyout')} onHistory={()=>setDialog('history')} onReturn={()=>setDialog('return')} onLoss={()=>setDialog('loss')} onChange={()=>setDialog('change')} onRepair={()=>setDialog('repair')} onDeposit={()=>setDialog('deposit')} onExchange={()=>setDialog('exchange')} onReverse={paymentId=>run(()=>reversePayment(paymentId,'收款录入错误'),'收款已冲正')} onStatus={s=>run(()=>changeStatus(selected.id,s),'状态已更新')}/>}</Dialog>
  <Dialog open={dialog==='payment'} title="登记收款" onClose={()=>setDialog('detail')}>{selected&&<PaymentForm pending={pending} submit={value=>run(()=>collectPayment(selected.id,value),'收款已登记')}/>}</Dialog>
  <Dialog open={dialog==='renew'} title="办理部分设备续租" wide onClose={()=>setDialog('detail')}>{selected&&<RenewalForm rental={selected} pending={pending} submit={values=>run(()=>renewRentalItems(selected.id,values),'续租已办理')}/>}</Dialog>
  <Dialog open={dialog==='history'} title="客户���史记录" wide onClose={()=>setDialog('detail')}>{selected&&<CustomerHistory phone={selected.customerPhone}/>}</Dialog>
  <Dialog open={dialog==='return'} title="办理设备退租" onClose={()=>setDialog('detail')}>{selected&&<OperationForm rental={selected} mode="return" pending={pending} submit={value=>run(()=>returnRentalItem(value as ReturnInput),'退租已登记')}/>}</Dialog>
  <Dialog open={dialog==='loss'} title="登记设备丢失" onClose={()=>setDialog('detail')}>{selected&&<OperationForm rental={selected} mode="loss" pending={pending} submit={value=>run(()=>reportLostItem(value as LossInput),'丢失已登记')}/>}</Dialog>
  <Dialog open={dialog==='change'} title="变更配置与租金" wide onClose={()=>setDialog('detail')}>{selected&&<ChangeForm rental={selected} pending={pending} submit={value=>run(()=>changeRentalItem(value),'配置与应收已更新')}/>}</Dialog>
  <Dialog open={dialog==='repair'} title="登记维修单" wide onClose={()=>setDialog('detail')}>{selected&&<RepairForm rental={selected} pending={pending} submit={value=>run(()=>createRepairRecord(value),'维修记录已保存')}/>}</Dialog>
  <Dialog open={dialog==='deposit'} title="押金退还或抵扣" onClose={()=>setDialog('detail')}>{selected&&<DepositForm rental={selected} pending={pending} submit={(type,amount,date,notes)=>run(()=>recordDepositAction(selected.id,type,amount,date,notes),'押金流水已登记')}/>}</Dialog>
  <Dialog open={dialog==='exchange'} title="设备换机调拨" onClose={()=>setDialog('detail')}>{selected&&<ExchangeForm rental={selected} pending={pending} submit={value=>run(()=>exchangeRentalItem(value),'换机调拨已登记')}/>}</Dialog>
  <Dialog open={dialog==='buyout'} title="办理部分买断" onClose={()=>setDialog('detail')}>{selected&&<BuyoutForm rental={selected} pending={pending} submit={(itemId,quantity,price,date,notes)=>run(()=>buyoutRentalItem(selected.id,itemId,quantity,price,date,notes),'买断已登记')}/>}</Dialog>
  </div>
}

const configs:Record<string,[keyof RentalItemInput,string,string][]>= {
  台式机:[['cpu','CPU','Intel i5-12400'],['motherboard','主板','华硕 B660M'],['memory','内存','16GB DDR4'],['storage','硬盘','512GB SSD'],['graphicsCard','显卡','RTX 3060'],['powerSupply','电源','550W'],['caseModel','机箱','MATX 机箱'],['monitorInfo','显示器','24 英寸']],
  笔记本:[['cpu','CPU','Core Ultra 7'],['memory','内存','16GB'],['storage','硬盘','1TB SSD'],['graphicsCard','显卡','Intel Arc'],['screenSize','屏幕尺寸','14 英寸'],['screenResolution','分辨率','2560 × 1600'],['batteryInfo','电池信息','57Wh / 健康度 95%'],['adapterInfo','适配器','65W Type-C']],
  显示器:[['screenSize','屏幕尺寸','27 英寸'],['screenResolution','分辨率','2560 × 1440'],['refreshRate','刷新率','165Hz'],['panelType','面板','IPS'],['colorGamut','色域','99% sRGB'],['ports','接口','HDMI / DP'],['monitorInfo','支架功能','升降旋转'],['accessories','配件','电源线、DP 线']],
  一体机:[['cpu','CPU','Intel i5'],['memory','内存','16GB'],['storage','硬盘','512GB SSD'],['graphicsCard','显卡','Intel UHD'],['screenSize','屏幕尺寸','24 英寸'],['screenResolution','分辨率','1920 × 1080'],['ports','接口','USB / HDMI / 网口'],['accessories','配件','无线键鼠']],
}
function RentalForm({form,setForm,submit,pending}:{form:RentalInput;setForm:(form:RentalInput)=>void;submit:()=>void;pending:boolean}){
  const updateItem=(index:number,key:keyof RentalItemInput,value:string|number)=>setForm({...form,items:form.items.map((item,i)=>i===index?{...item,[key]:value}:item)})
  const totals=form.items.reduce((a,i)=>({qty:a.qty+i.quantity,monthly:a.monthly+i.monthlyRent,total:a.total+i.totalRent}),{qty:0,monthly:0,total:0})
  return <form onSubmit={e=>{e.preventDefault();submit()}} className="flex flex-col gap-6"><FormSection title="合同与客户" description="一份合同可包含多项不同设备配置"><div className="grid gap-4 sm:grid-cols-2"><Field label="合同编号" value={form.contractNo} onChange={v=>setForm({...form,contractNo:v})}/><Field label="客户公司名称" value={form.customerCompany||''} onChange={v=>setForm({...form,customerCompany:v})} required={false}/><Field label="联系人姓名" value={form.customerName} onChange={v=>setForm({...form,customerName:v})}/><Field label="联系电话" value={form.customerPhone} onChange={v=>setForm({...form,customerPhone:v})}/><Field label="客户地址" value={form.customerAddress||''} onChange={v=>setForm({...form,customerAddress:v})} required={false}/></div></FormSection>
  <FormSection title={`设备明细（${form.items.length} 项）`} description="每项设备可独立设置配置、数量、月租和合同金额"><div className="flex flex-col gap-4">{form.items.map((item,index)=><div key={index} className="rounded-xl border bg-muted/30 p-4"><div className="mb-4 flex items-center justify-between"><h3 className="font-semibold">设备明细 {index+1}</h3>{form.items.length>1&&<button type="button" aria-label={`删除设备明细 ${index+1}`} onClick={()=>setForm({...form,items:form.items.filter((_,i)=>i!==index)})} className="rounded-lg border p-2 text-destructive"><Trash2 className="size-4"/></button>}</div><div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3"><label className="flex flex-col gap-2 text-sm font-medium">设备类型<select className="h-10 rounded-lg border bg-background px-3" value={item.deviceType} onChange={e=>updateItem(index,'deviceType',e.target.value)}>{['台式��','笔记本','显示器','一体机','其他'].map(v=><option key={v}>{v}</option>)}</select></label><Field label="设备名称 / 型号" value={item.deviceName} onChange={v=>updateItem(index,'deviceName',v)}/><Field label="设备编号 / 编号范围" value={item.deviceCode||''} onChange={v=>updateItem(index,'deviceCode',v)} required={false}/><Field label="数量" type="number" value={item.quantity} onChange={v=>updateItem(index,'quantity',Number(v))}/><Field label="月租金（元）" type="number" value={item.monthlyRent} onChange={v=>updateItem(index,'monthlyRent',Number(v))}/><Field label="明细合同金额（元）" type="number" value={item.totalRent} onChange={v=>updateItem(index,'totalRent',Number(v))}/></div>{configs[item.deviceType]&&<div className="mt-4 grid gap-4 sm:grid-cols-2 lg:grid-cols-4">{configs[item.deviceType].map(([key,label,placeholder])=><Field key={key} label={label} value={String(item[key]||'')} placeholder={placeholder} onChange={v=>updateItem(index,key,v)}/>)}</div>}<div className="mt-4"><Field label="其他配置" value={item.deviceConfig||''} onChange={v=>updateItem(index,'deviceConfig',v)} required={false}/></div></div>)}<button type="button" onClick={()=>setForm({...form,items:[...form.items,emptyItem()]})} className="flex h-10 items-center justify-center gap-2 rounded-lg border border-dashed font-medium"><Plus className="size-4"/>添加另一项设备</button></div></FormSection>
  <FormSection title="租期与费用" description="合计金额由各设备明细自动汇总"><div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3"><Field label="开始日期" type="date" value={form.startDate} onChange={v=>setForm({...form,startDate:v})}/><Field label="结束日期" type="date" value={form.endDate} onChange={v=>setForm({...form,endDate:v})}/><Field label="押金（元）" type="number" value={form.deposit} onChange={v=>setForm({...form,deposit:Number(v)})}/></div><div className="grid grid-cols-3 gap-3 rounded-xl bg-muted p-4 text-sm"><Info l="设备总数" v={`${totals.qty} 台`}/><Info l="月租合计" v={money(totals.monthly)}/><Info l="合同总额" v={money(totals.total)}/></div></FormSection><FormSection title="业务备注" description="填写交付要求、软件环境或其他约定"><textarea className="min-h-24 rounded-lg border bg-background p-3" value={form.notes||''} onChange={e=>setForm({...form,notes:e.target.value})}/></FormSection><button disabled={pending} className="h-11 self-end rounded-lg bg-primary px-6 font-medium text-primary-foreground disabled:opacity-60">{pending?'正在保存':'保存租赁合同'}</button></form>
}

function Detail({rental,onPayment,onRenew,onBuyout,onHistory,onReturn,onLoss,onChange,onRepair,onDeposit,onExchange,onReverse,onStatus}:{rental:Rental;onPayment:()=>void;onRenew:()=>void;onBuyout:()=>void;onHistory:()=>void;onReturn:()=>void;onLoss:()=>void;onChange:()=>void;onRepair:()=>void;onDeposit:()=>void;onExchange:()=>void;onReverse:(paymentId:number)=>void;onStatus:(s:string)=>void}){return <div className="flex flex-col gap-5"><div className="grid grid-cols-2 gap-4 rounded-xl bg-muted p-4 text-sm sm:grid-cols-4"><Info l="客户公司" v={rental.customerCompany||'个人客户'}/><Info l="联系人" v={rental.customerName}/><Info l="联系电话" v={rental.customerPhone}/><Info l="租期" v={`${rental.startDate} 至 ${rental.endDate}`}/><Info l="状态" v={rental.status}/><Info l="设备总数" v={`${rental.quantity} 台`}/><Info l="合同金额" v={money(rental.totalRent)}/><Info l="已收款" v={money(rental.paidAmount)}/><Info l="押金" v={money(rental.deposit)}/></div><div className="flex flex-col gap-3"><h3 className="font-semibold">设备明细</h3>{rental.items.map(item=>{const remain=item.quantity-item.boughtOutQuantity;return <article key={item.id} className="rounded-xl border p-4"><div className="flex flex-col justify-between gap-2 sm:flex-row"><div><p className="font-semibold">{item.deviceName}</p><p className="text-sm text-muted-foreground">{item.deviceType}{item.deviceCode?` · ${item.deviceCode}`:''}</p></div><Status value={remain===0?'已买断':item.boughtOutQuantity>0?'部分买断':'在租'}/></div><div className="mt-4 grid grid-cols-2 gap-3 text-sm sm:grid-cols-4"><Info l="原数量" v={`${item.quantity} 台`}/><Info l="已买断" v={`${item.boughtOutQuantity} 台`}/><Info l="剩余在租" v={`${remain} 台`}/><Info l="买断金额" v={money(item.buyoutAmount)}/><Info l="当前月租" v={money(item.monthlyRent)}/><Info l="设备租期" v={`${item.startDate||rental.startDate} 至 ${item.endDate||rental.endDate}`}/></div><p className="mt-3 text-sm text-muted-foreground">{configs[item.deviceType]?.map(([key,label])=>`${label}：${item[key]||'—'}`).join(' · ')||item.deviceConfig||'暂无配置'}</p></article>})}</div>{rental.bills.length>0&&<section><h3 className="mb-3 font-semibold">月度应收账单</h3><div className="flex flex-col gap-2">{rental.bills.map(bill=><div key={bill.id} className="flex flex-wrap items-center justify-between gap-2 rounded-lg border p-3 text-sm"><span>{bill.periodStart} 至 {bill.periodEnd} · {bill.billType}</span><span>{money(bill.paidAmount)} / {money(bill.amount)} · {bill.status}</span></div>)}</div></section>}{rental.paymentRecords.length>0&&<section><h3 className="mb-3 font-semibold">收款与冲正</h3><div className="flex flex-col gap-2">{rental.paymentRecords.map(payment=><div key={payment.id} className="flex flex-wrap items-center justify-between gap-2 rounded-lg border p-3 text-sm"><span>{payment.paymentDate} · {payment.feeType} · {money(payment.amount)}</span>{Number(payment.amount)>0&&<button type="button" onClick={()=>onReverse(payment.id)} className="rounded-lg border px-3 py-1.5 text-destructive">冲正</button>}</div>)}</div></section>}{rental.events.length>0&&<section><h3 className="mb-3 font-semibold">变更与维修记录</h3><div className="flex flex-col gap-2">{rental.events.map(event=><article key={event.id} className="rounded-lg border p-3 text-sm"><div className="flex flex-wrap items-center justify-between gap-2"><strong>{event.eventType} · {event.eventDate}</strong><Status value={event.status}/></div><p className="mt-1 text-muted-foreground">{event.eventType==='维修'?`${event.faultDescription||'维修记录'} · 客户承担 ${money(event.customerCharge)}`:`${event.reason||'配置调整'} · 应收调整 ${money(event.feeAdjustment)}`}</p><p className="mt-1 text-xs text-muted-foreground">经办人：{event.operatorName}{event.notes?` · ${event.notes}`:''}</p></article>)}</div></section>}{rental.renewalRecords.length>0&&<div><h3 className="mb-3 font-semibold">续租记录</h3><div className="flex flex-col gap-2">{rental.renewalRecords.map(record=>{const item=rental.items.find(i=>i.id===record.renewedRentalItemId)||rental.items.find(i=>i.id===record.sourceRentalItemId);return <div key={record.id} className="rounded-lg border p-3 text-sm"><div className="flex flex-col justify-between gap-1 sm:flex-row"><strong>{item?.deviceName||'设备明细'} · {record.quantity} 台 · 续租 {record.renewalMonths||'—'} 个月</strong><span>{record.renewalDate}</span></div><p className="mt-1 text-muted-foreground">月租 {money(record.oldMonthlyRent)} → {money(record.newMonthlyRent)} · 到期 {record.oldEndDate} → {record.newEndDate}</p></div>})}</div></div>}{rental.buyoutRecords.length>0&&<div><h3 className="mb-3 font-semibold">买断记录</h3><div className="flex flex-col gap-2">{rental.buyoutRecords.map(record=><div key={record.id} className="flex justify-between rounded-lg border p-3 text-sm"><span>{record.buyoutDate} · {record.quantity} 台 × {money(record.unitPrice)}</span><strong>{money(record.amount)}</strong></div>)}</div></div>}<div className="flex flex-wrap gap-2"><button onClick={onHistory} className="rounded-lg border px-4 py-2 text-sm font-medium">客户历史</button><button onClick={onReturn} className="rounded-lg border px-4 py-2 text-sm font-medium">办理退租</button><button onClick={onLoss} className="rounded-lg border px-4 py-2 text-sm font-medium text-destructive">登记丢失</button><Link href={`/contracts/${rental.id}`} className="inline-flex items-center gap-2 rounded-lg border px-4 py-2 text-sm font-medium"><FileText className="size-4"/>查看合同</Link><button onClick={onDeposit} className="rounded-lg border px-3 py-2 text-sm font-medium">押金处理</button><button onClick={onExchange} className="rounded-lg border px-3 py-2 text-sm font-medium">设备换机</button><button onClick={onChange} className="rounded-lg border px-3 py-2 text-sm font-medium">配置/租金变更</button><button onClick={onRepair} className="rounded-lg border px-3 py-2 text-sm font-medium">登记维修</button><button onClick={onPayment} className="rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground">登记收款</button><button onClick={onRenew} className="rounded-lg border px-4 py-2 text-sm font-medium">办理续租</button>{rental.items.some(i=>i.boughtOutQuantity<i.quantity)&&<button onClick={onBuyout} className="rounded-lg border px-4 py-2 text-sm font-medium">办理部分买断</button>}<button onClick={()=>onStatus('丢失')} className="rounded-lg border px-4 py-2 text-sm font-medium">标记丢失</button>{!['在租','买断'].includes(rental.status)&&<button onClick={()=>onStatus('在租')} className="rounded-lg border px-4 py-2 text-sm font-medium">恢复在租</button>}</div></div>}
function addMonths(date:string,months=1){const [year,month,day]=date.split('-').map(Number);const target=new Date(Date.UTC(year,month-1+months,1));const lastDay=new Date(Date.UTC(target.getUTCFullYear(),target.getUTCMonth()+1,0)).getUTCDate();target.setUTCDate(Math.min(day,lastDay));return target.toISOString().slice(0,10)}
function addDays(date:string,days=1){const value=new Date(`${date}T00:00:00Z`);value.setUTCDate(value.getUTCDate()+days);return value.toISOString().slice(0,10)}
function RenewalForm({rental,submit,pending}:{rental:Rental;submit:(values:RenewalInput[])=>void;pending:boolean}){
  const available=rental.items.filter(item=>item.quantity>item.boughtOutQuantity)
  const[rows,setRows]=useState<Record<number,RenewalInput>>({})
  const toggle=(item:Item)=>setRows(current=>{const next={...current};if(next[item.id])delete next[item.id];else{const end=item.endDate||rental.endDate;next[item.id]={rentalItemId:item.id,quantity:item.quantity-item.boughtOutQuantity,billingUnit:'month',duration:1,unitPrice:Number(item.monthlyRent),newEndDate:addMonths(end,1),notes:''}}return next})
  const update=(id:number,key:keyof RenewalInput,value:string|number)=>setRows(current=>({...current,[id]:{...current[id],[key]:value}}))
  const selected=Object.values(rows);const totalQty=selected.reduce((sum,row)=>sum+row.quantity,0);const renewalTotal=selected.reduce((sum,row)=>sum+row.quantity*row.unitPrice*row.duration,0)
  return <form onSubmit={e=>{e.preventDefault();submit(selected)}} className="flex flex-col gap-4"><div className="rounded-xl bg-muted p-4 text-sm text-muted-foreground">勾选需要续租的设备，可分别填写续租数量、续租月数和新月租，新到期日将自动计算。部分数量续租时系统会自动拆分，未续租设备保留原租金和到期日。</div><div className="flex flex-col gap-3">{available.map(item=>{const row=rows[item.id];const max=item.quantity-item.boughtOutQuantity;return <article key={item.id} className={`rounded-xl border p-4 ${row?'border-primary bg-primary/5':''}`}><label className="flex cursor-pointer items-start gap-3"><input className="mt-1 size-4" type="checkbox" checked={Boolean(row)} onChange={()=>toggle(item)}/><span><strong>{item.deviceName}</strong><span className="block text-sm text-muted-foreground">{item.deviceType} · 可续租 {max} 台 · 当前月租 {money(item.monthlyRent)} · 到期 {item.endDate||rental.endDate}</span></span></label>{row&&<div className="mt-4 grid gap-4 sm:grid-cols-2 lg:grid-cols-5"><Field label="续租数量" type="number" value={row.quantity} onChange={v=>update(item.id,'quantity',Number(v))}/><label className="flex flex-col gap-2 text-sm font-medium">计费方式<select className="h-10 rounded-lg border bg-background px-3" value={row.billingUnit} onChange={e=>{const unit=e.target.value as 'month'|'day';setRows(current=>({...current,[item.id]:{...current[item.id],billingUnit:unit,duration:1,unitPrice:unit==='month'?Number(item.monthlyRent):Math.round(Number(item.monthlyRent)/30*100)/100,newEndDate:unit==='month'?addMonths(item.endDate||rental.endDate,1):addDays(item.endDate||rental.endDate,1)}}))}}><option value="month">按月</option><option value="day">按天</option></select></label><Field label={`续租${row.billingUnit==='month'?'月数':'天数'}`} type="number" value={row.duration} onChange={v=>{const duration=Math.max(1,Math.floor(Number(v)));setRows(current=>({...current,[item.id]:{...current[item.id],duration,newEndDate:row.billingUnit==='month'?addMonths(item.endDate||rental.endDate,duration):addDays(item.endDate||rental.endDate,duration)}}))}}/><Field label={`每${row.billingUnit==='month'?'月':'天'}单价（元）`} type="number" value={row.unitPrice} onChange={v=>update(item.id,'unitPrice',Number(v))}/><div className="rounded-lg border bg-muted/50 px-3 py-2"><p className="text-sm font-medium">新到期日</p><p className="mt-1 font-semibold">{row.newEndDate}</p><p className="mt-1 text-xs text-muted-foreground">本项 {money(row.quantity*row.unitPrice*row.duration)}</p></div></div>}{row&&row.quantity>max&&<p className="mt-2 text-sm text-destructive">续租数量不能超过 {max} 台</p>}</article>})}</div>{available.length===0&&<p className="py-8 text-center text-sm text-muted-foreground">当前没有可续租设备</p>}<div className="grid grid-cols-2 gap-3 rounded-xl bg-muted p-4"><Info l="本次续租" v={`${totalQty} 台`}/><Info l="续租金额" v={money(renewalTotal)}/></div><button disabled={pending||selected.length===0||selected.some(row=>{const item=available.find(i=>i.id===row.rentalItemId);return !item||row.quantity<=0||row.quantity>item.quantity-item.boughtOutQuantity||row.duration<1||row.duration>3650||row.unitPrice<0||row.newEndDate<=(item.endDate||rental.endDate)})} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-50">{pending?'处理中':'确认续租'}</button></form>
}
function PaymentForm({submit,pending}:{submit:(value:PaymentInput)=>void;pending:boolean}){const[value,setValue]=useState<PaymentInput>({amount:0,paymentDate:today(),paymentMethod:'微信',feeType:'原合同租金',notes:''});return <form onSubmit={e=>{e.preventDefault();submit(value)}} className="flex flex-col gap-4"><div className="grid gap-4 sm:grid-cols-2"><Field label="收款金额（元）" type="number" value={value.amount} onChange={v=>setValue({...value,amount:Number(v)})}/><Field label="收款日期" type="date" value={value.paymentDate} onChange={v=>setValue({...value,paymentDate:v})}/><label className="flex flex-col gap-2 text-sm font-medium">支付方式<select className="h-10 rounded-lg border bg-background px-3" value={value.paymentMethod} onChange={e=>setValue({...value,paymentMethod:e.target.value as PaymentInput['paymentMethod']})}>{['现金','微信','支付宝','银行卡','其他'].map(item=><option key={item}>{item}</option>)}</select></label><label className="flex flex-col gap-2 text-sm font-medium">费用类型<select className="h-10 rounded-lg border bg-background px-3" value={value.feeType} onChange={e=>setValue({...value,feeType:e.target.value as PaymentInput['feeType']})}>{['原合同租金','续租费','押金','买断费','其他'].map(item=><option key={item}>{item}</option>)}</select></label></div><label className="flex flex-col gap-2 text-sm font-medium">备注<textarea className="min-h-20 rounded-lg border bg-background p-3" value={value.notes||''} onChange={e=>setValue({...value,notes:e.target.value})}/></label><button disabled={pending||value.amount<=0} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-50">{pending?'处理中':'确认收款'}</button></form>}
function CustomerHistory({phone}:{phone:string}){const[data,setData]=useState<Awaited<ReturnType<typeof getCustomerHistory>>|null>(null);const[error,setError]=useState('');useEffect(()=>{getCustomerHistory(phone).then(setData).catch(e=>setError(e instanceof Error?e.message:'查询失败'))},[phone]);if(error)return <p className="text-sm text-destructive">{error}</p>;if(!data)return <p className="py-10 text-center text-sm text-muted-foreground">正在查询客户历史…</p>;const contractMap=new Map(data.contracts.map(c=>[c.id,c.contractNo]));const total=data.contracts.reduce((sum,c)=>sum+Number(c.totalRent),0);const paid=data.payments.reduce((sum,p)=>sum+Number(p.amount),0);return <div className="flex flex-col gap-5"><div className="grid grid-cols-2 gap-3 rounded-xl bg-muted p-4 sm:grid-cols-4"><Info l="手机号" v={phone}/><Info l="历史合同" v={`${data.contracts.length} 份`}/><Info l="累计合同额" v={money(total)}/><Info l="累计收款" v={money(paid)}/></div><section><h3 className="mb-3 font-semibold">合同记录</h3><div className="flex flex-col gap-2">{data.contracts.map(c=><div key={c.id} className="flex flex-col justify-between gap-2 rounded-lg border p-3 text-sm sm:flex-row"><span><strong>{c.contractNo}</strong> · {c.customerName}</span><span>{c.startDate} 至 {c.endDate} · {money(c.totalRent)} · {c.status}</span></div>)}</div></section><section><h3 className="mb-3 font-semibold">续租记录</h3><div className="flex flex-col gap-2">{data.renewals.map(r=><div key={r.id} className="rounded-lg border p-3 text-sm"><strong>{contractMap.get(r.rentalId)} · {r.quantity} 台 · 按{r.billingUnit==='day'?'天':'月'}续租 {r.duration||r.renewalMonths||1} {r.billingUnit==='day'?'天':'个月'}</strong><p className="mt-1 text-muted-foreground">单价 {money(r.unitPrice||r.newMonthlyRent)} · 金额 {money(r.renewalAmount)} · 到期 {r.newEndDate}</p></div>)}{!data.renewals.length&&<p className="text-sm text-muted-foreground">暂无续租记录</p>}</div></section><section><h3 className="mb-3 font-semibold">付款记录</h3><div className="flex flex-col gap-2">{data.payments.map(p=><div key={p.id} className="flex flex-col justify-between gap-1 rounded-lg border p-3 text-sm sm:flex-row"><span><strong>{money(p.amount)}</strong> · {p.feeType} · {p.paymentMethod}</span><span>{contractMap.get(p.rentalId)} · {p.paymentDate}{p.notes?` · ${p.notes}`:''}</span></div>)}{!data.payments.length&&<p className="text-sm text-muted-foreground">暂无付款记录</p>}</div></section></div>}
function OperationForm({rental,mode,submit,pending}:{rental:Rental;mode:'return'|'loss';submit:(value:ReturnInput|LossInput)=>void;pending:boolean}){const available=rental.items.filter(i=>i.quantity-i.boughtOutQuantity-i.returnedQuantity-i.lostQuantity>0);const[itemId,setItemId]=useState(available[0]?.id||0);const[quantity,setQuantity]=useState(1);const[date,setDate]=useState(today());const[condition,setCondition]=useState<'完好'|'轻微磨损'|'损坏'>('完好');const[amount,setAmount]=useState(0);const[refund,setRefund]=useState(0);const[notes,setNotes]=useState('');return <form onSubmit={e=>{e.preventDefault();const base={rentalId:rental.id,rentalItemId:itemId,quantity,date,notes};submit(mode==='return'?{...base,condition,deductionAmount:amount,depositRefund:refund}:{...base,unitCompensation:amount})}} className="flex flex-col gap-4"><label className="flex flex-col gap-2 text-sm font-medium">设备明细<select value={itemId} onChange={e=>setItemId(Number(e.target.value))} className="h-10 rounded-lg border bg-background px-3">{available.map(i=><option key={i.id} value={i.id}>{i.deviceName}（可处理 {i.quantity-i.boughtOutQuantity-i.returnedQuantity-i.lostQuantity} 台）</option>)}</select></label><div className="grid grid-cols-2 gap-4"><Field label="数量" type="number" value={quantity} onChange={v=>setQuantity(Number(v))}/><Field label={mode==='return'?'归还日期':'发生日期'} type="date" value={date} onChange={setDate}/>{mode==='return'&&<label className="flex flex-col gap-2 text-sm font-medium">设备状况<select value={condition} onChange={e=>setCondition(e.target.value as typeof condition)} className="h-10 rounded-lg border bg-background px-3"><option>完好</option><option>轻微磨损</option><option>损坏</option></select></label>}<Field label={mode==='return'?'损坏/清洁扣款（元）':'单台赔偿（元）'} type="number" value={amount} onChange={v=>setAmount(Number(v))}/>{mode==='return'&&<Field label="押金退还（元）" type="number" value={refund} onChange={v=>setRefund(Number(v))}/>}</div><label className="flex flex-col gap-2 text-sm font-medium">备注<textarea className="min-h-20 rounded-lg border bg-background p-3" value={notes} onChange={e=>setNotes(e.target.value)}/></label><button disabled={pending||!available.length} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground">{pending?'处理中':mode==='return'?'确认退租':'确认丢失'}</button></form>}
function DepositForm({rental,submit,pending}:{rental:Rental;submit:(type:'押金退还'|'押金抵扣欠租'|'押金抵扣赔偿',amount:number,date:string,notes:string)=>void;pending:boolean}){const[value,setValue]=useState({type:'押金退还' as '押金退还'|'押金抵扣欠租'|'押金抵扣赔偿',amount:0,date:today(),notes:''});const balance=rental.ledger.reduce((sum,entry)=>sum+(entry.entryType==='押金收取'?Number(entry.amount):entry.entryType.startsWith('押金')?-Math.abs(Number(entry.amount)):0),0);return <form onSubmit={e=>{e.preventDefault();submit(value.type,value.amount,value.date,value.notes)}} className="flex flex-col gap-4"><p className="rounded-lg bg-muted p-3 text-sm">当前可用押金余额：<strong>{money(balance)}</strong></p><label className="flex flex-col gap-2 text-sm font-medium">处理类型<select className="h-10 rounded-lg border bg-background px-3" value={value.type} onChange={e=>setValue({...value,type:e.target.value as typeof value.type})}><option>押金退还</option><option>押金抵扣欠租</option><option>押金抵扣赔偿</option></select></label><Field label="金额（元）" type="number" value={value.amount} onChange={amount=>setValue({...value,amount:Number(amount)})}/><Field label="处理日期" type="date" value={value.date} onChange={date=>setValue({...value,date})}/><Field label="原因或凭证备注" value={value.notes} onChange={notes=>setValue({...value,notes})}/><button disabled={pending} className="h-10 rounded-lg bg-primary font-medium text-primary-foreground disabled:opacity-50">确认处理</button></form>}
function ExchangeForm({rental,submit,pending}:{rental:Rental;submit:(value:ExchangeInput)=>void;pending:boolean}){const[itemId,setItemId]=useState(rental.items[0]?.id||0);const[value,setValue]=useState({exchangeDate:today(),newDeviceName:'',newDeviceCode:'',newDeviceConfig:'',reason:'',notes:''});return <form onSubmit={e=>{e.preventDefault();submit({rentalId:rental.id,rentalItemId:itemId,...value})}} className="flex flex-col gap-4"><label className="flex flex-col gap-2 text-sm font-medium">原设备<select className="h-10 rounded-lg border bg-background px-3" value={itemId} onChange={e=>setItemId(Number(e.target.value))}>{rental.items.map(item=><option key={item.id} value={item.id}>{item.deviceName} · {item.deviceCode||'无编号'}</option>)}</select></label><Field label="换机日期" type="date" value={value.exchangeDate} onChange={exchangeDate=>setValue({...value,exchangeDate})}/><Field label="新设备名称 / 型号" value={value.newDeviceName} onChange={newDeviceName=>setValue({...value,newDeviceName})}/><Field label="新设备编号" value={value.newDeviceCode} onChange={newDeviceCode=>setValue({...value,newDeviceCode})}/><Field label="新设备配置" value={value.newDeviceConfig} onChange={newDeviceConfig=>setValue({...value,newDeviceConfig})} required={false}/><Field label="换机原因" value={value.reason} onChange={reason=>setValue({...value,reason})}/><Field label="备注" value={value.notes} onChange={notes=>setValue({...value,notes})} required={false}/><button disabled={pending} className="h-10 rounded-lg bg-primary font-medium text-primary-foreground disabled:opacity-50">确认换机</button></form>}
function ChangeForm({rental,submit,pending}:{rental:Rental;submit:(value:RentalChangeInput)=>void;pending:boolean}){const[itemId,setItemId]=useState(rental.items[0]?.id||0);const item=rental.items.find(current=>current.id===itemId)||rental.items[0];const[value,setValue]=useState({eventDate:today(),reason:'',feeAdjustment:0,notes:''});if(!item)return <p>暂无可变更设备</p>;return <form onSubmit={e=>{e.preventDefault();submit({rentalId:rental.id,itemId:item.id,eventDate:value.eventDate,reason:value.reason,feeAdjustment:value.feeAdjustment,notes:value.notes,deviceName:item.deviceName,deviceCode:item.deviceCode||'',deviceConfig:item.deviceConfig||'',cpu:item.cpu||'',motherboard:item.motherboard||'',memory:item.memory||'',storage:item.storage||'',graphicsCard:item.graphicsCard||'',powerSupply:item.powerSupply||'',caseModel:item.caseModel||'',monitorInfo:item.monitorInfo||'',accessories:item.accessories||'',monthlyRent:Number(item.monthlyRent),totalRent:Number(item.totalRent)})}} className="flex flex-col gap-4"><label className="flex flex-col gap-2 text-sm font-medium">设备明细<select value={itemId} onChange={e=>setItemId(Number(e.target.value))} className="h-10 rounded-lg border bg-background px-3">{rental.items.map(current=><option key={current.id} value={current.id}>{current.deviceName}</option>)}</select></label><div className="grid gap-4 sm:grid-cols-2"><Field label="变更日期" type="date" value={value.eventDate} onChange={eventDate=>setValue({...value,eventDate})}/><Field label="变更原因" value={value.reason} onChange={reason=>setValue({...value,reason})}/><Field label="设备名称 / 型号" value={item.deviceName} onChange={deviceName=>Object.assign(item,{deviceName})}/><Field label="设备编号" value={item.deviceCode||''} onChange={deviceCode=>Object.assign(item,{deviceCode})} required={false}/><Field label="CPU" value={item.cpu||''} onChange={cpu=>Object.assign(item,{cpu})} required={false}/><Field label="内存" value={item.memory||''} onChange={memory=>Object.assign(item,{memory})} required={false}/><Field label="硬盘" value={item.storage||''} onChange={storage=>Object.assign(item,{storage})} required={false}/><Field label="显卡 / 配件品牌" value={item.graphicsCard||''} onChange={graphicsCard=>Object.assign(item,{graphicsCard})} required={false}/><Field label="当前月租（元）" type="number" value={item.monthlyRent} onChange={monthlyRent=>Object.assign(item,{monthlyRent})}/><Field label="调整后明细总额（元���" type="number" value={item.totalRent} onChange={totalRent=>Object.assign(item,{totalRent})}/><Field label="本次应收调整（可填负数）" type="number" value={value.feeAdjustment} onChange={feeAdjustment=>setValue({...value,feeAdjustment:Number(feeAdjustment)})}/></div><label className="flex flex-col gap-2 text-sm font-medium">其他配置<textarea className="min-h-20 rounded-lg border bg-background p-3" value={item.deviceConfig||''} onChange={e=>Object.assign(item,{deviceConfig:e.target.value})}/></label><button disabled={pending} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-50">{pending?'处理中':'确认变更'}</button></form>}
function RepairForm({rental,submit,pending}:{rental:Rental;submit:(value:RepairInput)=>void;pending:boolean}){const[value,setValue]=useState<RepairInput>({rentalId:rental.id,itemId:rental.items[0]?.id||0,eventDate:today(),status:'待维修',faultDescription:'',resolution:'',repairCost:0,customerCharge:0,completedDate:'',notes:''});return <form onSubmit={e=>{e.preventDefault();submit(value)}} className="flex flex-col gap-4"><div className="grid gap-4 sm:grid-cols-2"><label className="flex flex-col gap-2 text-sm font-medium">设备明细<select value={value.itemId} onChange={e=>setValue({...value,itemId:Number(e.target.value)})} className="h-10 rounded-lg border bg-background px-3">{rental.items.map(item=><option key={item.id} value={item.id}>{item.deviceName}</option>)}</select></label><Field label="报修日期" type="date" value={value.eventDate} onChange={eventDate=>setValue({...value,eventDate})}/><label className="flex flex-col gap-2 text-sm font-medium">维修状态<select value={value.status} onChange={e=>setValue({...value,status:e.target.value as RepairInput['status']})} className="h-10 rounded-lg border bg-background px-3"><option>待维修</option><option>维修中</option><option>已完成</option></select></label><Field label="完成日期" type="date" value={value.completedDate||''} onChange={completedDate=>setValue({...value,completedDate})} required={false}/><Field label="维修总费用（元）" type="number" value={value.repairCost} onChange={repairCost=>setValue({...value,repairCost:Number(repairCost)})}/><Field label="客户承担金额（元）" type="number" value={value.customerCharge} onChange={customerCharge=>setValue({...value,customerCharge:Number(customerCharge)})}/></div><label className="flex flex-col gap-2 text-sm font-medium">故障描述<textarea required className="min-h-20 rounded-lg border bg-background p-3" value={value.faultDescription} onChange={e=>setValue({...value,faultDescription:e.target.value})}/></label><label className="flex flex-col gap-2 text-sm font-medium">处理方式<textarea className="min-h-20 rounded-lg border bg-background p-3" value={value.resolution||''} onChange={e=>setValue({...value,resolution:e.target.value})}/></label><label className="flex flex-col gap-2 text-sm font-medium">备注<textarea className="min-h-20 rounded-lg border bg-background p-3" value={value.notes||''} onChange={e=>setValue({...value,notes:e.target.value})}/></label><button disabled={pending} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-50">{pending?'处理中':'保存维修单'}</button></form>}
function BuyoutForm({rental,submit,pending}:{rental:Rental;submit:(itemId:number,quantity:number,price:number,date:string,notes:string)=>void;pending:boolean}){const available=rental.items.filter(i=>i.boughtOutQuantity<i.quantity);const[itemId,setItemId]=useState(available[0]?.id||0);const[quantity,setQuantity]=useState(1);const[price,setPrice]=useState(0);const[date,setDate]=useState(today());const[notes,setNotes]=useState('');const item=available.find(i=>i.id===itemId);return <form onSubmit={e=>{e.preventDefault();submit(itemId,quantity,price,date,notes)}} className="flex flex-col gap-4"><label className="flex flex-col gap-2 text-sm font-medium">设备明细<select className="h-11 rounded-lg border bg-background px-3" value={itemId} onChange={e=>{setItemId(Number(e.target.value));setQuantity(1)}}>{available.map(i=><option key={i.id} value={i.id}>{i.deviceName}（剩余 {i.quantity-i.boughtOutQuantity} 台）</option>)}</select></label><div className="grid grid-cols-2 gap-4"><Field label="买断数量" type="number" value={quantity} onChange={v=>setQuantity(Number(v))}/><Field label="买断单价（元）" type="number" value={price} onChange={v=>setPrice(Number(v))}/><Field label="买断日期" type="date" value={date} onChange={setDate}/><div className="rounded-lg bg-muted p-3"><p className="text-xs text-muted-foreground">本次买断金额</p><p className="mt-1 text-lg font-semibold">{money(quantity*price)}</p></div></div>{item&&quantity>item.quantity-item.boughtOutQuantity&&<p className="text-sm text-destructive">买断数量不能超过剩余 {item.quantity-item.boughtOutQuantity} 台</p>}<label className="flex flex-col gap-2 text-sm font-medium">备注<textarea className="min-h-20 rounded-lg border bg-background p-3" value={notes} onChange={e=>setNotes(e.target.value)}/></label><button disabled={pending||!item||quantity<=0||price<=0||quantity>(item.quantity-item.boughtOutQuantity)} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-50">{pending?'处理中':'确认买断'}</button></form>}
function Dialog({open,title,children,onClose,wide=false}:{open:boolean;title:string;children:React.ReactNode;onClose:()=>void;wide?:boolean}){if(!open)return null;return <div className="fixed inset-0 z-50 flex items-center justify-center bg-foreground/20 p-4" onMouseDown={e=>{if(e.currentTarget===e.target)onClose()}}><div role="dialog" aria-modal="true" aria-label={title} className={`max-h-[92svh] w-full overflow-y-auto rounded-2xl border bg-card shadow-xl ${wide?'max-w-5xl':'max-w-lg'}`}><div className="sticky top-0 z-10 flex items-center justify-between border-b bg-card p-4"><h2 className="text-lg font-semibold">{title}</h2><button aria-label="关闭" onClick={onClose} className="rounded-lg p-2 hover:bg-muted"><X className="size-5"/></button></div><div className="p-4 sm:p-6">{children}</div></div></div>}
function FormSection({title,description,children}:{title:string;description:string;children:React.ReactNode}){return <fieldset className="flex flex-col gap-4 rounded-xl border p-4"><legend className="px-2 font-semibold">{title}</legend><p className="text-sm text-muted-foreground">{description}</p>{children}</fieldset>}
function Field({label,value,onChange,type='text',required=true,placeholder}:{label:string;value:string|number;onChange:(value:string)=>void;type?:string;required?:boolean;placeholder?:string}){return <label className="flex flex-col gap-2 text-sm font-medium">{label}<input className="h-10 rounded-lg border bg-background px-3 outline-none focus:ring-2 focus:ring-primary" type={type} value={value} onChange={e=>onChange(e.target.value)} required={required} placeholder={placeholder} min={type==='number'&&label!=='本次应收调整（可填负数）'?'0':undefined} step={type==='number'?'0.01':undefined}/></label>}
function Stat({label,value,icon}:{label:string;value:string|number;icon:React.ReactNode}){return <div className="rounded-xl border bg-card p-4"><div className="mb-3 flex size-9 items-center justify-center rounded-lg bg-muted text-primary">{icon}</div><p className="text-sm text-muted-foreground">{label}</p><p className="mt-1 text-xl font-bold">{value}</p></div>}
function Status({value}:{value:string}){return <span className="inline-flex w-fit rounded-full bg-muted px-2.5 py-1 text-xs font-medium">{value}</span>}
function Info({l,v}:{l:string;v:string}){return <div><p className="text-xs text-muted-foreground">{l}</p><p className="mt-1 font-medium">{v}</p></div>}
function QuickAction({label,type,onSubmit,pending}:{label:string;type:string;onSubmit:(value:string)=>void;pending:boolean}){const[value,setValue]=useState('');return <form onSubmit={e=>{e.preventDefault();onSubmit(value)}} className="flex flex-col gap-4"><Field label={label} type={type} value={value} onChange={setValue}/><button disabled={pending} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground">{pending?'处理中':'确认提交'}</button></form>}
